var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배는? 아직도 못 찾은 거야?","JPN":"先輩は？　まだ見つかっていないの？","ENG":"Where's Shiyoon? You haven't found him yet?","TWN":"前輩呢？還是沒找到人嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네. 지난 주말 이후로 주시윤 씨의 흔적은 오리무중이에요.","JPN":"はい。先週末からアキヤマさんの行方は五里霧中です。","ENG":"I'm afraid not. He vanished without a trace, gone since last weekend.","TWN":"還沒，周時雲從上週末開始就行蹤不明。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L5_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"미나 양이 주시윤 씨를 마지막으로 봤다던 헬리포트는 큰 싸움이라도 난 것처럼 파괴되어 있었어요.","JPN":"ミナさんが最後にアキヤマさんを見たヘリポートは、大規模戦闘でもあったかのように破壊されていました。","ENG":"The heliport where he was last seen was in shambles, as if a big fight occurred.","TWN":"米娜你最後一次看到周時雲的直升機場，就像經歷第三次世界大戰一樣像個廢墟。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"주변에 설치된 CCTV들도 강력한 침식파에 노출된 것처럼 데이터가 모두 망가진 상태였고요.","JPN":"周辺の防犯カメラも強力な侵食波を受けたかのように、全てのデータが破損していました。","ENG":"I checked all the CCTVs nearby, but the data had been corrupted, as if it was exposed to Corruption Rays.","TWN":"周圍裝設的監視器，也像暴露在出強烈侵蝕波當中一樣，資料全都毀損。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"최선을 다해 찾고 있지만……. 아직까지는 수사에 이렇다 할 진전이 없네요.","JPN":"最善を尽くして捜索していますが……まだこれといった進展はありませんね。","ENG":"We're trying our best... But we haven't had much progress yet.","TWN":"我們已經盡力去找，但……目前還沒有進展。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럴 수가…….","JPN":"そんな……","ENG":"Dang...","TWN":"怎麼會這樣……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"안 되겠어! 나라도 직접 가서……!","JPN":"やっぱりこのままじゃダメ！　私が直接……！","ENG":"Alright, that's it. I'll just go there myself and...","TWN":"不行！我要自己去找……!"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"쓸데없는 짓은 그만두세요, 미나 양.","JPN":"無駄な行動はやめてください、ミナさん。","ENG":"I wouldn't waste your energy.","TWN":"米娜，請你不要輕舉妄動。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"쓸데없는 짓이라니!","JPN":"無駄ってどういうこと！？","ENG":"How could you call this a waste?!","TWN":"什麼輕舉妄動！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부사장님은 나보다 선배랑 더 오래 일했잖아. 그런데 걱정도 안 돼?","JPN":"副社長は私よりも先輩との付き合いが長いでしょう？　心配にならないの？","ENG":"You've worked with Shiyoon much longer than I have. Aren't you even a bit worried?","TWN":"副總你和前輩共事的時間比我還久，難道你都不擔心前輩嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서 무슨 수로 시윤 군을 찾겠다는 거죠?","JPN":"それで、どうやってアキヤマ君を探すつもりですか？","ENG":"So how do you think you'll find him, exactly?","TWN":"所以你打算怎麼找到他？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"설마 이 넓은 도시를 혼자서 헤집고 다니겠다는 건가요?","JPN":"まさか、この広い都市を一人で手当たり次第探すとでも？","ENG":"You're not thinking of rummaging through this huge city by yourself, are you?","TWN":"這個城市這麼大，你打算自己一個人去找嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇지만…… 이렇게 기다려 봤자 아무 소식도 없잖아!","JPN":"でも……こうして待っているばかりじゃ何も進まないじゃない！","ENG":"But... Sitting around like this won't get us anywhere!","TWN":"我只是……我們這樣等也沒有任何消息不是嗎！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"조바심을 낸다고 사라진 시윤 군이 갑자기 나타나진 않습니다.","JPN":"焦ったところで消えたアキヤマ君が突然戻ってくることはありません。","ENG":"Neither will getting antsy.","TWN":"就算我著急，時雲也不會因此就突然出現。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지금은 믿고 기다려 보죠. 전문 인력들이 수사를 맡고 있으니까요.","JPN":"捜査は専門家に任せて、今は信じて待ちましょう。","ENG":"For now, let's try to be patient. We've got professionals on the case.","TWN":"既然都已經派人出去找，我們現在能做的就是等待。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래요. 저희도 최선을 다해서 찾아 볼게요.","JPN":"そうですよ。私たちも全力で捜索します。","ENG":"Indeed. We'll also try our best to find him.","TWN":"沒錯，我們也會盡全力去找的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어쨌거나 리플레이서 사태 때 그 난리를 같이 겪었던 사이잖아요.","JPN":"なんだかんだ、リプレイサー事件のあの大騒ぎを一緒に乗り越えた仲ですから。","ENG":"After all, we went through thick and thin during that Replacers fiasco.","TWN":"畢竟我們也在克隆集團事件中一起並肩作戰過的嘛！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"본청에서 인력도 더 배정해 준다고 했으니까, 조만간 단서가 나올 거예요.","JPN":"本庁も人員を追加補充すると言っているので、近いうちに手がかりが見つかると思いますよ。","ENG":"Top brass said they'd assign more personnel to the search effort, so we should find a lead soon.","TWN":"總部那邊說會再加派人手去找，說不定很快就會有好消息！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알겠습니다. 잘 부탁드립니다, 형사님.","JPN":"わかりました。よろしくお願いします、刑事さん。","ENG":"I see. Thank you, detective.","TWN":"好的，警官大人，萬事拜託。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자, 경찰이 수사를 하는 동안 우리는 우리 일을 하죠.","JPN":"さあ、警察が捜査している間、私たちは私たちの仕事をしましょう。","ENG":"While the police proceed with their investigation, let's conduct our own.","TWN":"在警察幫忙尋找時雲下落的同時，我們也不能閒著。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"시윤 군이 실종된 건 안타깝지만, 그렇다고 언제까지 회사 업무를 미뤄 둘 수는 없으니까요.","JPN":"アキヤマ君が行方不明になったのは残念ですが、\\nだからといっていつまでも業務を後回しにするわけにはいきません。","ENG":"As unfortunate it is that Shiyoon went missing, we can't keep putting off our work.","TWN":"時雲失蹤的事大家都很遺憾，但公司的事也不能一直放著不管吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 저와 스승님은 따로 할 일이 있는 터라 펜릴 소대가 작전을 진행하긴 어렵겠군요.","JPN":"しかし、私と師匠は他にやるべき仕事があるので、フェンリル小隊に作戦を任せるのは難しそうですね。","ENG":"Having said that, the Master and I've got something else to attend to... so it will be difficult for Fenrir Squad to conduct the next mission.","TWN":"不過我和師父另外有事，芬里爾小隊可能無法進行作戰。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알트 소대와 에디 소대는 각각 계약된 작전을 맡아 진행해주시기 바랍니다.","JPN":"アルト小隊とエディー小隊はそれぞれ契約した作戦を遂行してください。","ENG":"I'd like to ask ALT Squad and Eddie Squad to proceed with their respective operations, per their contracts.","TWN":"阿爾特小隊和艾迪小隊請各自進行已簽約的作戰。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양은 임시로 알트 소대에 배속하겠습니다.","JPN":"ミナさんは一時的にアルト小隊に配属します。","ENG":"As for you, Mina, let's assign you with ALT Squad for now.","TWN":"米娜就暫時先加入阿爾特小隊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……알겠습니다, 부사장님.","JPN":"……わかりました、副社長。","ENG":"...Very well, ma'am.","TWN":"……是，副總。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그런데 정말 괜찮겠어?","JPN":"でも本当にいいの？","ENG":"Are you sure about this?","TWN":"這樣真的沒關係嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그 소년, 뻔뻔하긴 해도 나쁜 녀석은 아닌 것 같았는데.","JPN":"あの少年、厚かましいところはあるけど悪い子じゃなかったわよ。","ENG":"The kid seemed a bit cheeky, but he wasn't so bad after all.","TWN":"那個孩子雖然臉皮厚，但不是個壞孩子。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네. 제가 아는 시윤 군은 절대로 어디서 쉽게 당할 녀석이 아닙니다.","JPN":"はい。私の知っているアキヤマ君は、そう簡単にやられるような人ではありません。","ENG":"I guess. I'm confident that Shiyoon can handle himself out there.","TWN":"是的，我所認識的時雲是絕對不會輕易就倒下的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"모르죠. 어쩌면 아무 일 없었다는 듯이 머리나 긁적이면서 나타날지도.","JPN":"もしかしたら何事もなかったように、頭を掻きながらしれっと戻ってくるかもしれません。","ENG":"Who knows? He might just turn up, scratching his head as if nothing happened.","TWN":"誰知道呢？說不定他會一副沒事的樣子，搔著頭出現在我們面前呢？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"시윤 군에 대한 소식이 있으면 바로 연락하도록 하겠습니다.","JPN":"アキヤマ君に関することは進展があり次第、すぐ連絡します。","ENG":"I'll let you all know immediately if I hear any updates on Shiyoon.","TWN":"一有時雲的消息就會立刻通知你們。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그럼 다들 해산하죠.","JPN":"それでは、解散しましょう。","ENG":"All right, then. Please get to work.","TWN":"大家原地解散吧！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"마음에 없는 소리를 잘도 하더군. 두고 볼 생각은 전혀 없으면서.","JPN":"思ってもいないことをよく言えるな。人に任せるつもりはさらさら無いくせに。","ENG":"So, you managed to talk all that nonsense with a straight face. I know you're not going to just sit back and watch.","TWN":"你倒是很會說一些違心之論嘛，明明就沒有要坐視不管的意思。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양이 끼어들면 일이 더 복잡해질 것 같아 배제했을 뿐입니다.","JPN":"ミナさんがかかわると余計複雑になりそうなので排除しただけです。","ENG":"I only left Mina out of this because her involvement would complicate things.","TWN":"讓米娜插手的話事情只會變得更複雜而已。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"좋든 싫든 시윤 군의 목을 비트는 건 부사장인 제 권한이니까요.","JPN":"良くも悪くも、アキヤマ君の首をどうするかは副社長である私の権限ですから。","ENG":"Whether I like it or not, it's my job as Vice President to handle Shiyoon.","TWN":"時雲的生死只能由我這個副總來決定！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"감히 제 사원들을 멋대로 건드린 놈들에게 대가를 치르게 해 줘야죠.","JPN":"うちの社員に勝手に手を出したやつには、代償を払わせてやらないと。","ENG":"I'll make them pay for daring to mess with my employees.","TWN":"膽敢來招惹我的員工，我要叫你們付出血的代價！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 미나 양이 없는 편이 스승님도 더 편하지 않으신가요?","JPN":"師匠だってミナさんがいないほうが楽ではありませんか？","ENG":"Besides, doesn't it keep things simple for you too without Mina around?","TWN":"而且，沒有米娜師父你也比較好做事不是嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……그렇다고 해 두지.","JPN":"……そういうことにしておこう。","ENG":"...I won't deny that.","TWN":"……你說那樣就那樣吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"단서는 찾았나?","JPN":"手がかりは見つかったか？","ENG":"Found any leads yet?","TWN":"目前有找到什麼線索嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"물증은 없지만 심증은 있습니다.","JPN":"物証はありませんが、心当たりはあります。","ENG":"There is no evidence but a strong suspicion.","TWN":"雖然沒有證據，但我心裡有底。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아마 지난번 스승님을 습격한 그 <color=#ffd34c>강령술사</color>의 패거리겠죠.","JPN":"おそらく、この前師匠を襲撃した<color=#ffd34c>降霊術師</color>の一味でしょう。","ENG":"My money's on that <color=#ffd34c>necromancer</color>'s gang who attacked you last time.","TWN":"應該和上次突襲師父的那個<color=#ffd34c>降靈術師</color>是一夥的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래. 나도 같은 생각이다.","JPN":"そうだな、私も同じ考えだ。","ENG":"Indeed. I'm with you on that.","TWN":"嗯，我也覺得。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사건이 정리된 뒤에 구 관리국 시절 전투 기록을 조금 찾아 봤습니다.","JPN":"事件が一段落した後、旧管理局時代の戦闘記録を少しあさってみました。","ENG":"I did a little digging in the Old Administration’s combat database.","TWN":"理出頭緒後，我有稍微翻一下舊管理局時期的戰鬥記錄。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"소실된 분량이 많아 정확하지는 않지만, 아마 <color=#ffd34c>사도</color> 중 한 명인 것 같더군요.","JPN":"消失した情報が多く正確ではありませんが、おそらく<color=#ffd34c>使徒</color>の一人のようです。","ENG":"Although I can't say for sure given the spotty data, I think we're dealing with one of the <color=#ffd34c>Apostles</color>.","TWN":"雖然當中有許多記錄遺失無法確認，但我猜應該是<color=#ffd34c>使徒</color>中的其中一位。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하긴, 그 정도가 아니면 스승님을 상대로 그렇게 시간을 끌 수 없었겠지만요.","JPN":"まあ、その程度でなければ師匠を相手にあれほど時間を稼ぐことはできなかったでしょう。","ENG":"Naturally, it'd take something like an Apostle to keep you occupied.","TWN":"也是，沒那點能耐的話，怎麼能和師父交手那麼久呢？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"세계침식률은 아직 임계점을 넘지 않았습니다.","JPN":"世界侵食率はまだ臨界点を超えていません。","ENG":"The Global Corruption rate hasn't exceeded the threshold yet.","TWN":"世界侵蝕率還沒超過臨界點。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아무리 사도라고 해도, 지금 단계에서 사용할 수 있는 힘은 제한적이어야 정상이죠.","JPN":"いくら使徒とはいえ、現段階で使用できる力に限界があるのが普通でしょう。","ENG":"Apostle or not, there should be a cap on the power they can tap into at this stage... normally.","TWN":"就算是使徒，目前可以使用的力量應該還是受限的才對。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 그 강령술사는……. 본신의 힘을 상당한 수준까지 사용할 수 있는 것처럼 보이더군요.","JPN":"しかしあの降霊術師は……本来の力を相当なレベルまで使えるように見えました。","ENG":"But with that necromancer... She seemed to be capable of accessing a considerable portion of her full power.","TWN":"但那個降靈術師……似乎可以使用自己的力量到某種程度。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아마도 놈의 주인을 봉인하던 방주에 심각한 문제가 발생한 모양입니다.","JPN":"おそらく、やつの主を封印していた箱舟に深刻な問題が発生したようです。","ENG":"It's likely that something went very wrong with the Ark that was detaining her master.","TWN":"看樣子應該是封印那傢伙主人的方舟發生嚴重的問題。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너, 방주에 대해서도 알고 있었나? 누가 가르쳐 준 거지?","JPN":"お前、箱舟について知っていたのか？　誰に教えてもらった？","ENG":"You knew about the Ark? Who told you?","TWN":"你也知道方舟的事？是誰告訴你的？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사업하는 사람에게 함부로 정보원을 물어보는 건 실례입니다, 스승님.","JPN":"ビジネスをしている人相手に気兼ねなく情報源を聞くのは失礼ですよ、師匠。","ENG":"You know it's frowned upon to ask businesspeople about their sources, Master.","TWN":"師父，我身為一位專業人士，怎麼可以透露線民的身分呢？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 지금은 그런 것보다 더 중요한 게 있죠.","JPN":"そして今は、そんなことよりもっと重要な仕事があります。","ENG":"We also have more important issues at hand.","TWN":"而且現在有比線民身分更重要的事吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"해당 방주의 좌표를 알려드리겠습니다.","JPN":"その箱舟の座標を教えます。","ENG":"I'll give you the coordinates to the Ark in question.","TWN":"這是那個方舟的座標。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 곳에 이번 사태 해결에 도움을 줄 조력자가 기다리고 있을 겁니다.","JPN":"そこで今回の事件解決のための協力者が待っているはずです。","ENG":"There, you'll find an asset who'll prove most helpful in solving this case.","TWN":"小幫手已經在那裡等師父囉！他對這次的事件會很有幫助的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"조력자? 누구 말이지?","JPN":"協力者？　誰のことだ？","ENG":"Asset? Who?","TWN":"很有幫助？誰說的？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"가 보면 알게 되실 겁니다. 스승님도 잘 알고 계시는 인물이니까요.","JPN":"行けばわかります。師匠もよくご存じの人ですから。","ENG":"You'll see when you get there. It's someone you know very well.","TWN":"等見到他就知道囉～這個人師父也認識的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아 참. 말씀드리는 걸 잊을 뻔했군요.","JPN":"ああ、そうだ。お伝えするのを忘れるところでした。","ENG":"Oh, right. I almost forgot to mention.","TWN":"哎呀～還有件事差點忘記跟師父說！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"드래곤 버스터, 이번에는 꼭 챙겨가도록 하세요.","JPN":"ドラゴンバスター、今回は必ず持って行ってください。","ENG":"Don't forget your Dragon Buster this time.","TWN":"這次記得要帶上屠龍者喔！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……알겠다.","JPN":"……わかった。","ENG":"...Fine.","TWN":"……嗯嗯。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};